/**
 * @fileoverview Shared JIT style fragments and factories.
 *
 * Provides reusable string constants and parameterised builders for
 * recurring JIT utility patterns found across multiple components.
 *
 * @module shared/styleFragments
 */

// ── Atomic Constants ────────────────────────────────────────────────────

/** Flex-1 truncated text with ellipsis — used by 8+ components. */
export const TRUNCATE = 'flex-1 min-w-0 overflow-hidden [text-overflow:ellipsis] text-nowrap';

/** Thin scrollbar with theme-aware thumb colour. */
export const SCROLLBAR_THIN = 'scrollbar-thin scrollbar-color-[var(--rui-thumb)_transparent]';

/** Scrollable body container — flex-1, overflow-y, thin scrollbar. */
export const SCROLL_BODY = 'flex-1 [min-height:0] [overflow-y:auto] ' + SCROLLBAR_THIN;

/** Fast background + colour transition (0.15 s). */
export const TRANSITION_COLORS = '[transition:background_.15s,color_.15s]';

/** Interactive-speed transition (0.1 s ease). */
export const TRANSITION_INTERACTIVE = '[transition:background_0.1s_ease,color_0.1s_ease]';

/** Icon-button reset — flex-centred, border-less, transparent, pointer. */
export const ICON_BTN_RESET = 'flex items-center justify-center p-0 [border:none] bg-transparent cursor-pointer shrink-0';

/** Focus ring (3 px) on :focus — accent border + shadow. */
export const FOCUS_RING = 'focus:[border-color:var(--rui-accent)] focus:[box-shadow:0_0_0_3px_var(--rui-accent-subtle)] [outline:none]';

/** Small focus ring (2 px) on :focus — accent border + shadow. */
export const FOCUS_RING_SM = 'focus:[border-color:var(--rui-accent)] focus:[box-shadow:0_0_0_2px_var(--rui-accent-subtle)] [outline:none]';

/** Disabled state — muted opacity + not-allowed cursor. */
export const DISABLED = '{is-disabled}:[opacity:0.6] {is-disabled}:cursor-not-allowed';

// ── Factories ───────────────────────────────────────────────────────────

/**
 * Selected-state accent triple (bg + fg + bold).
 * @param {string} p  CSS custom-property prefix (e.g. 'dp', 'dt')
 */
export const selectedState = (p) =>
    `{is-selected}:bg-[var(--${p}-accent)] {is-selected}:fg-[var(--${p}-on-accent)] {is-selected}:fw-600`;

/**
 * Focus ring with component-scoped accent tokens.
 * @param {string} p      CSS property prefix
 * @param {string} [size] Ring size (default '3px')
 * @param {string} [pseudo] CSS pseudo-class (default 'focus')
 */
export const focusRing = (p, size = '3px', pseudo = 'focus') =>
    `${pseudo}:[border-color:var(--${p}-accent)] ${pseudo}:[box-shadow:0_0_0_${size}_var(--${p}-accent-subtle)]`;

/**
 * Editor-style toolbar bar (flex, wrap, gap, bg-raised, border-bottom).
 * Used by MarkdownEditor, GridEditor, LayoutEditor.
 * @param {string} p  CSS custom-property prefix (e.g. 'me', 'ge', 'le')
 */
export const editorToolbar = (p) =>
    `flex items-center [flex-wrap:wrap] gap-[var(--${p}-toolbar-gap)] [padding:var(--${p}-toolbar-padding)] bg-[var(--${p}-bg-raised)] [border-bottom:1px_solid_var(--${p}-border)]`;

/**
 * Editor-style root container (flex-col, min-height, border, rounded, overflow).
 * Used by GridEditor, LayoutEditor.
 * @param {string} p  CSS custom-property prefix (e.g. 'ge', 'le')
 */
export const editorRoot = (p) =>
    `relative flex flex-col [min-height:var(--${p}-min-height)] bg-[var(--${p}-bg)] fg-[var(--${p}-text)] [font-family:inherit] text-[var(--${p}-font-size)] [border:1px_solid_var(--${p}-border)] rounded-[var(--${p}-radius)] overflow-hidden`;
